SELECT CODIGO,NOMBRE,ANO,SALDO0, SALDO1, SALDO2, SALDO3, SALDO4, SALDO5, SALDO6, SALDO7, SALDO8, SALDO9, SALDO10, SALDO11, SALDO12, SALDO13, NETO0, NETO1, NETO2, NETO3, NETO4, NETO5, NETO6, NETO7, NETO8, NETO9, NETO10, NETO11, NETO12, NETO13, DEBITO0, DEBITO1, DEBITO2, DEBITO3, DEBITO4, DEBITO5, DEBITO6, DEBITO7, DEBITO8, DEBITO9, DEBITO10, DEBITO11, DEBITO12, DEBITO13, CREDITO0, CREDITO1, CREDITO2, CREDITO3, CREDITO4, CREDITO5, CREDITO6, CREDITO7, CREDITO8, CREDITO9, CREDITO10, CREDITO11, CREDITO12, CREDITO13, AJUSTE0, AJUSTE1, AJUSTE2, AJUSTE3, AJUSTE4, AJUSTE5, AJUSTE6, AJUSTE7, AJUSTE8, AJUSTE9, AJUSTE10, AJUSTE11, AJUSTE12, AJUSTE13,  (DEBITO0+DEBITO1+DEBITO2+DEBITO3+DEBITO4+DEBITO5+DEBITO6+DEBITO7+DEBITO8+DEBITO9+DEBITO10+DEBITO11+DEBITO12+DEBITO13) TOTAL_DEBITO, (CREDITO0+CREDITO1+CREDITO2+CREDITO3+CREDITO4+CREDITO5+CREDITO6+CREDITO7+CREDITO8+CREDITO9+CREDITO10+CREDITO11+CREDITO12+CREDITO13) TOTAL_CREDITO 
FROM V_PLAN_CONTABLE 
WHERE COMPANIA= s$compania$s
AND  ANO= s$anio$s
AND ID= 's$cuenta$s'
